"use client";

import { useEffect, useMemo, useRef, useState } from 'react';
import { useAdminStore } from '@/lib/store/admin-store';
import {
  AdminQuestion,
  AddExplanationRequest,
  AddTipRequest,
  CreateQuestionRequest,
  QuestionExplanation,
  QuestionOption,
  UpdateQuestionRequest,
  UpdateTipRequest,
} from '@/lib/types/admin';
import {
  AlertCircle,
  Check,
  CheckCircle,
  ChevronDown,
  ChevronUp,
  Edit,
  Film,
  FileText,
  FileUp,
  Globe2,
  GripVertical,
  Image,
  Info,
  Loader2,
  Plus,
  Search,
  Sparkles,
  Trash2,
  Upload,
  XCircle,
} from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Dialog, DialogContent, DialogFooter, DialogHeader, DialogTitle } from '@/components/ui/dialog';

type LocaleCode = 'en' | 'am' | 'ti';
type AssetType = 'image' | 'video' | 'document' | 'diagram' | 'illustration' | 'question_image';

interface LocalizedText {
  en: string;
  am: string;
  ti: string;
}

function moveItem<T>(items: T[], fromIndex: number, toIndex: number): T[] {
  if (toIndex < 0 || toIndex >= items.length || fromIndex === toIndex) {
    return items;
  }
  const clone = [...items];
  const [moved] = clone.splice(fromIndex, 1);
  clone.splice(toIndex, 0, moved);
  return clone;
}

function LocalAssetPreview({ file }: { file: File }) {
  const [previewUrl, setPreviewUrl] = useState('');

  useEffect(() => {
    const nextUrl = URL.createObjectURL(file);
    setPreviewUrl(nextUrl);
    return () => URL.revokeObjectURL(nextUrl);
  }, [file]);

  if (file.type.startsWith('image/')) {
    return <img src={previewUrl} alt={file.name} className="h-20 w-full rounded-md object-cover" />;
  }

  if (file.type.startsWith('video/')) {
    return (
      <video controls className="h-20 w-full rounded-md object-cover">
        <source src={previewUrl} type={file.type} />
      </video>
    );
  }

  return (
    <div className="flex h-20 items-center justify-center rounded-md border bg-muted/40">
      {file.type.includes('pdf') || file.type.includes('document') ? (
        <FileText className="h-6 w-6 text-muted-foreground" />
      ) : (
        <Film className="h-6 w-6 text-muted-foreground" />
      )}
    </div>
  );
}

interface OptionFormState {
  id?: number;
  text: string;
  isCorrect: boolean;
  position: number;
  translations: LocalizedText;
}

interface AssetDraft {
  file: File;
  type: AssetType;
  alt: string;
  caption: string;
}

interface QuestionFormState {
  jurisdictionId: number;
  categoryId?: number;
  question: string;
  translations: LocalizedText;
  active: boolean;
  assets: AssetDraft[];
}

const LANGUAGES: { code: LocaleCode; label: string }[] = [
  { code: 'en', label: 'English' },
  { code: 'am', label: 'Amharic' },
  { code: 'ti', label: 'Tigrinya' },
];

const emptyLocaleText = (): LocalizedText => ({ en: '', am: '', ti: '' });

const createBlankOption = (position: number): OptionFormState => ({
  text: '',
  isCorrect: false,
  position,
  translations: emptyLocaleText(),
});

const createInitialForm = (): QuestionFormState => ({
  jurisdictionId: 0,
  categoryId: undefined,
  question: '',
  translations: emptyLocaleText(),
  active: true,
  assets: [],
});

const mapQuestionToForm = (question: AdminQuestion): QuestionFormState => ({
  jurisdictionId: question.jurisdictionId,
  categoryId: question.categoryId,
  question: question.question,
  translations: {
    en: question.translations?.en?.question ?? question.question,
    am: question.translations?.am?.question ?? '',
    ti: question.translations?.ti?.question ?? '',
  },
  active: question.active,
  assets: [],
});

function buildQuestionTranslations(input: LocalizedText) {
  return {
    en: { question: input.en },
    ...(input.am.trim() ? { am: { question: input.am } } : {}),
    ...(input.ti.trim() ? { ti: { question: input.ti } } : {}),
  };
}

function buildOptionTranslations(input: LocalizedText) {
  return {
    en: { text: input.en },
    ...(input.am.trim() ? { am: { text: input.am } } : {}),
    ...(input.ti.trim() ? { ti: { text: input.ti } } : {}),
  };
}

function buildTipTranslations(input: LocalizedText) {
  return {
    en: { tip: input.en },
    ...(input.am.trim() ? { am: { tip: input.am } } : {}),
    ...(input.ti.trim() ? { ti: { tip: input.ti } } : {}),
  };
}

function buildExplanationTranslations(input: LocalizedText) {
  return {
    en: { text: input.en },
    ...(input.am.trim() ? { am: { text: input.am } } : {}),
    ...(input.ti.trim() ? { ti: { text: input.ti } } : {}),
  };
}

function validateFiles(files: File[]): string | null {
  const allowedTypes = [
    'image/jpeg',
    'image/png',
    'image/gif',
    'image/webp',
    'image/svg+xml',
    'video/mp4',
    'video/webm',
    'video/ogg',
    'application/pdf',
    'application/msword',
    'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
  ];
  for (const file of files) {
    if (!allowedTypes.includes(file.type)) {
      return `Unsupported file type: ${file.name}`;
    }
    if (file.size > 10 * 1024 * 1024) {
      return `File is too large (max 10MB): ${file.name}`;
    }
  }
  return null;
}

export default function QuestionsPage() {
  const {
    questions,
    licenceCategories,
    jurisdictions,
    categories,
    isLoading,
    error,
    clearError,
    fetchQuestions,
    fetchQuestion,
    fetchCategories,
    fetchJurisdictions,
    fetchLicenceCategories,
    createQuestion,
    updateQuestion,
    deleteQuestion,
    uploadQuestionAssets,
    deleteQuestionAsset,
    addOption,
    updateOption,
    deleteOption,
    uploadOptionImage,
    deleteOptionImage,
    createExplanation,
    fetchExplanationByQuestion,
    updateExplanation,
    deleteExplanation,
    uploadExplanationAssets,
    deleteExplanationAsset,
    addTip,
    updateTip,
    deleteTip,
  } = useAdminStore();

  const [search, setSearch] = useState('');
  const [filterCategoryId, setFilterCategoryId] = useState<number | ''>('');
  const [filterJurisdictionId, setFilterJurisdictionId] = useState<number | ''>('');
  const [filterLicenceCategoryId, setFilterLicenceCategoryId] = useState<number | ''>('');
  const [filterActive, setFilterActive] = useState<boolean | ''>('');
  const [currentPage, setCurrentPage] = useState(0);
  const pageSize = 20;

  const [questionForm, setQuestionForm] = useState<QuestionFormState>(createInitialForm());
  const [questionLocale, setQuestionLocale] = useState<LocaleCode>('en');
  const [formMode, setFormMode] = useState<'create' | 'edit'>('create');
  const [editingQuestion, setEditingQuestion] = useState<AdminQuestion | null>(null);
  const [formOpen, setFormOpen] = useState(false);

  const [detailsOpen, setDetailsOpen] = useState(false);
  const [selectedQuestion, setSelectedQuestion] = useState<AdminQuestion | null>(null);
  const [currentExplanation, setCurrentExplanation] = useState<QuestionExplanation | null>(null);
  const [explanationLocale, setExplanationLocale] = useState<LocaleCode>('en');
  const [tipLocale, setTipLocale] = useState<LocaleCode>('en');

  const [newOptionDraft, setNewOptionDraft] = useState<OptionFormState>(createBlankOption(1));
  const [explanationDraft, setExplanationDraft] = useState<LocalizedText>(emptyLocaleText());
  const [tipDraft, setTipDraft] = useState<LocalizedText>(emptyLocaleText());
  const [explanationAssetDrafts, setExplanationAssetDrafts] = useState<AssetDraft[]>([]);

  const [deleteOpen, setDeleteOpen] = useState(false);
  const [questionToDelete, setQuestionToDelete] = useState<AdminQuestion | null>(null);

  const [feedback, setFeedback] = useState<{ type: 'success' | 'error'; message: string } | null>(null);
  const [draggingQuestionAssetIndex, setDraggingQuestionAssetIndex] = useState<number | null>(null);
  const [draggingExplanationAssetIndex, setDraggingExplanationAssetIndex] = useState<number | null>(null);

  const questionPrimaryRef = useRef<HTMLTextAreaElement | null>(null);
  const detailsPrimaryRef = useRef<HTMLTextAreaElement | null>(null);
  const deleteButtonRef = useRef<HTMLButtonElement | null>(null);

  const filteredQuestions = useMemo(
    () =>
      (questions?.content ?? []).filter((question) => {
        if (!search.trim()) return true;
        const q = search.toLowerCase();
        return question.question.toLowerCase().includes(q) || String(question.id).includes(q);
      }),
    [questions, search]
  );

  useEffect(() => {
    void Promise.all([
      fetchJurisdictions(),
      fetchCategories(),
      fetchLicenceCategories({ page: 0, size: 200 }),
    ]);
  }, [fetchJurisdictions, fetchCategories, fetchLicenceCategories]);

  useEffect(() => {
    void loadQuestions();
  }, [currentPage, filterCategoryId, filterJurisdictionId, filterLicenceCategoryId, filterActive]);

  useEffect(() => {
    if (!formOpen) return;
    const t = window.setTimeout(() => questionPrimaryRef.current?.focus(), 30);
    return () => window.clearTimeout(t);
  }, [formOpen]);

  useEffect(() => {
    if (!detailsOpen) return;
    const t = window.setTimeout(() => detailsPrimaryRef.current?.focus(), 30);
    return () => window.clearTimeout(t);
  }, [detailsOpen]);

  useEffect(() => {
    if (!deleteOpen) return;
    const t = window.setTimeout(() => deleteButtonRef.current?.focus(), 30);
    return () => window.clearTimeout(t);
  }, [deleteOpen]);

  const loadQuestions = async () => {
    const params: Record<string, string | number | boolean> = { page: currentPage, size: pageSize };
    if (filterCategoryId !== '') params.categoryId = filterCategoryId;
    if (filterJurisdictionId !== '') params.jurisdictionId = filterJurisdictionId;
    if (filterLicenceCategoryId !== '') params.licenceCategoryId = filterLicenceCategoryId;
    if (filterActive !== '') params.active = filterActive;
    await fetchQuestions(params);
  };

  const openCreateDialog = () => {
    setFormMode('create');
    setEditingQuestion(null);
    setQuestionLocale('en');
    setQuestionForm(createInitialForm());
    setFormOpen(true);
  };

  const openEditDialog = async (question: AdminQuestion) => {
    const full = await fetchQuestion(question.id);
    setFormMode('edit');
    setEditingQuestion(full);
    setQuestionLocale('en');
    setQuestionForm(mapQuestionToForm(full));
    setFormOpen(true);
  };

  const openDetailsDialog = async (question: AdminQuestion) => {
    const full = await fetchQuestion(question.id);
    setSelectedQuestion(full);
    setNewOptionDraft(createBlankOption(Math.max(1, full.options.length + 1)));
    setTipDraft(emptyLocaleText());
    setExplanationDraft(emptyLocaleText());
    setExplanationAssetDrafts([]);

    try {
      const explanation = await fetchExplanationByQuestion(full.id);
      setCurrentExplanation(explanation);
      setExplanationDraft({
        en: explanation.text ?? explanation.explanation ?? '',
        am: explanation.translations?.am?.text ?? explanation.translations?.am?.explanation ?? '',
        ti: explanation.translations?.ti?.text ?? explanation.translations?.ti?.explanation ?? '',
      });
    } catch {
      setCurrentExplanation(null);
    }

    setDetailsOpen(true);
  };

  const appendQuestionAssets = (files: File[]) => {
    const validationError = validateFiles(files);
    if (validationError) {
      setFeedback({ type: 'error', message: validationError });
      return;
    }

    setQuestionForm((prev) => ({
      ...prev,
      assets: [
        ...prev.assets,
        ...files.map((file) => ({ file, type: 'image' as AssetType, alt: '', caption: '' })),
      ],
    }));
  };

  const appendExplanationAssets = (files: File[]) => {
    const validationError = validateFiles(files);
    if (validationError) {
      setFeedback({ type: 'error', message: validationError });
      return;
    }

    setExplanationAssetDrafts((prev) => [
      ...prev,
      ...files.map((file) => ({ file, type: 'image' as AssetType, alt: '', caption: '' })),
    ]);
  };

  const validateQuestionForm = () => {
    if (!questionForm.jurisdictionId) {
      return 'Jurisdiction is required.';
    }
    if (!questionForm.question.trim() || questionForm.question.trim().length < 10) {
      return 'Question text must be at least 10 characters.';
    }
    return null;
  };

  const handleSaveQuestion = async () => {
    const validationError = validateQuestionForm();
    if (validationError) {
      setFeedback({ type: 'error', message: validationError });
      return;
    }

    try {
      let questionId: number;
      let createdQuestion: AdminQuestion | null = null;

      if (formMode === 'create') {
        const payload: CreateQuestionRequest = {
          jurisdictionId: questionForm.jurisdictionId,
          categoryId: questionForm.categoryId,
          question: questionForm.question,
          translations: buildQuestionTranslations({
            en: questionForm.translations.en || questionForm.question,
            am: questionForm.translations.am,
            ti: questionForm.translations.ti,
          }),
          active: questionForm.active,
        };

        const created = await createQuestion(payload);
        questionId = created.id;
        createdQuestion = created;
      } else {
        if (!editingQuestion) return;

        const payload: UpdateQuestionRequest = {
          jurisdictionId: questionForm.jurisdictionId,
          categoryId: questionForm.categoryId,
          question: questionForm.question,
          translations: buildQuestionTranslations({
            en: questionForm.translations.en || questionForm.question,
            am: questionForm.translations.am,
            ti: questionForm.translations.ti,
          }),
          active: questionForm.active,
        };

        await updateQuestion(editingQuestion.id, payload);

        questionId = editingQuestion.id;
      }

      if (questionForm.assets.length > 0) {
        await uploadQuestionAssets(
          questionId,
          questionForm.assets.map((asset) => asset.file),
          {
            assetTypes: questionForm.assets.map((asset) => asset.type),
            alts: questionForm.assets.map((asset) => asset.alt),
            captions: questionForm.assets.map((asset) => asset.caption),
          }
        );
      }

      await loadQuestions();
      setFormOpen(false);
      setFeedback({
        type: 'success',
        message:
          formMode === 'create'
            ? 'Step 1 complete. Question created. Continue in details to add options, explanation, and tips.'
            : 'Question updated successfully.',
      });

      if (formMode === 'create' && createdQuestion) {
        await openDetailsDialog(createdQuestion);
      }
    } catch (err: any) {
      setFeedback({ type: 'error', message: err?.response?.data?.message ?? 'Failed to save question.' });
    }
  };

  const handleDeleteQuestion = async () => {
    if (!questionToDelete) return;
    try {
      await deleteQuestion(questionToDelete.id);
      setDeleteOpen(false);
      setQuestionToDelete(null);
      await loadQuestions();
      setFeedback({ type: 'success', message: 'Question deleted successfully.' });
    } catch (err: any) {
      setFeedback({ type: 'error', message: err?.response?.data?.message ?? 'Failed to delete question.' });
    }
  };

  const refreshSelectedQuestion = async () => {
    if (!selectedQuestion) return;
    const refreshed = await fetchQuestion(selectedQuestion.id);
    setSelectedQuestion(refreshed);
  };

  const handleAddOptionInDetails = async () => {
    if (!selectedQuestion) return;
    if (!newOptionDraft.text.trim()) {
      setFeedback({ type: 'error', message: 'Option text is required.' });
      return;
    }

    try {
      await addOption(selectedQuestion.id, {
        text: newOptionDraft.text,
        isCorrect: newOptionDraft.isCorrect,
        position: newOptionDraft.position,
        translations: buildOptionTranslations({
          en: newOptionDraft.translations.en || newOptionDraft.text,
          am: newOptionDraft.translations.am,
          ti: newOptionDraft.translations.ti,
        }),
      });
      await refreshSelectedQuestion();
      setNewOptionDraft(createBlankOption((selectedQuestion.options?.length ?? 0) + 1));
      setFeedback({ type: 'success', message: 'Option added.' });
    } catch (err: any) {
      setFeedback({ type: 'error', message: err?.response?.data?.message ?? 'Failed to add option.' });
    }
  };

  const handleUpdateOptionInDetails = async (option: QuestionOption) => {
    try {
      await updateOption(option.id, {
        text: option.text,
        isCorrect: option.isCorrect,
        position: option.position,
        translations: option.translations,
      });
      await refreshSelectedQuestion();
      setFeedback({ type: 'success', message: 'Option updated.' });
    } catch (err: any) {
      setFeedback({ type: 'error', message: err?.response?.data?.message ?? 'Failed to update option.' });
    }
  };

  const handleSaveExplanation = async () => {
    if (!selectedQuestion) return;
    const text = explanationDraft.en.trim();
    if (text.length < 20) {
      setFeedback({ type: 'error', message: 'Explanation text must be at least 20 characters.' });
      return;
    }

    try {
      let explanationId = currentExplanation?.id;
      const payload: AddExplanationRequest = {
        questionId: selectedQuestion.id,
        text,
        translations: buildExplanationTranslations(explanationDraft),
      };

      if (currentExplanation) {
        await updateExplanation(currentExplanation.id, {
          text,
          translations: buildExplanationTranslations(explanationDraft),
        });
      } else {
        const created = await createExplanation(payload);
        explanationId = created.id;
      }

      if (explanationId && explanationAssetDrafts.length > 0) {
        await uploadExplanationAssets(
          explanationId,
          explanationAssetDrafts.map((asset) => asset.file),
          {
            assetTypes: explanationAssetDrafts.map((asset) => asset.type),
            alts: explanationAssetDrafts.map((asset) => asset.alt),
            captions: explanationAssetDrafts.map((asset) => asset.caption),
          }
        );
      }

      const refreshed = await fetchExplanationByQuestion(selectedQuestion.id);
      setCurrentExplanation(refreshed);
      setExplanationAssetDrafts([]);
      setFeedback({ type: 'success', message: 'Explanation saved.' });
    } catch (err: any) {
      setFeedback({ type: 'error', message: err?.response?.data?.message ?? 'Failed to save explanation.' });
    }
  };

  const handleAddTip = async () => {
    if (!selectedQuestion) return;
    const tip = tipDraft.en.trim();
    if (tip.length < 10) {
      setFeedback({ type: 'error', message: 'Tip must be at least 10 characters.' });
      return;
    }

    try {
      const payload: AddTipRequest = {
        tip,
        translations: buildTipTranslations(tipDraft),
      };
      await addTip(selectedQuestion.id, payload);
      await refreshSelectedQuestion();
      setTipDraft(emptyLocaleText());
      setFeedback({ type: 'success', message: 'Tip added.' });
    } catch (err: any) {
      setFeedback({ type: 'error', message: err?.response?.data?.message ?? 'Failed to add tip.' });
    }
  };

  return (
    <div className="space-y-6 pb-10">
      <section className="relative overflow-hidden rounded-2xl border border-border/70 bg-gradient-to-br from-sky-100/80 via-cyan-50/70 to-emerald-100/80 p-6 shadow-sm dark:from-slate-900 dark:via-slate-950 dark:to-emerald-950">
        <div className="absolute -right-16 -top-16 h-44 w-44 rounded-full bg-cyan-300/25 blur-3xl dark:bg-cyan-600/20" />
        <div className="absolute -bottom-20 left-20 h-56 w-56 rounded-full bg-emerald-300/20 blur-3xl dark:bg-emerald-700/20" />
        <div className="relative z-10 flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
          <div>
            <div className="mb-2 inline-flex items-center gap-2 rounded-full border border-cyan-400/40 bg-background/70 px-3 py-1 text-xs font-medium">
              <Sparkles className="h-3.5 w-3.5" />
              Admin Question Studio
            </div>
            <h1 className="text-2xl font-semibold tracking-tight sm:text-3xl">/backoffice/questions</h1>
            <p className="mt-2 text-sm text-muted-foreground sm:text-base">
              Full management for questions, options, explanations, tips, assets, and translations.
            </p>
          </div>
          <Button onClick={openCreateDialog} className="gap-2">
            <Plus className="h-4 w-4" />
            Create Question
          </Button>
        </div>
      </section>

      {feedback ? (
        <div
          aria-live="polite"
          className={`flex items-start gap-2 rounded-xl border px-4 py-3 text-sm ${
            feedback.type === 'success'
              ? 'border-emerald-500/40 bg-emerald-500/10 text-emerald-700 dark:text-emerald-300'
              : 'border-red-500/40 bg-red-500/10 text-red-700 dark:text-red-300'
          }`}
        >
          {feedback.type === 'success' ? <CheckCircle className="mt-0.5 h-4 w-4" /> : <AlertCircle className="mt-0.5 h-4 w-4" />}
          <span>{feedback.message}</span>
          <button className="ml-auto text-xs underline" onClick={() => setFeedback(null)}>
            Dismiss
          </button>
        </div>
      ) : null}

      {error ? (
        <div className="flex items-center gap-2 rounded-xl border border-red-500/40 bg-red-500/10 px-4 py-3 text-sm text-red-700 dark:text-red-300">
          <AlertCircle className="h-4 w-4" />
          <span>{error}</span>
          <button className="ml-auto text-xs underline" onClick={clearError}>
            Clear
          </button>
        </div>
      ) : null}

      <section className="rounded-2xl border bg-card/80 p-4 shadow-sm backdrop-blur">
        <div className="mb-3 flex items-center gap-2 text-sm font-medium text-muted-foreground">
          <Search className="h-4 w-4" />
          Filters
        </div>
        <div className="grid grid-cols-1 gap-3 md:grid-cols-2 xl:grid-cols-5">
          <div className="relative xl:col-span-2">
            <Search className="pointer-events-none absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
            <input
              value={search}
              onChange={(e) => setSearch(e.target.value)}
