                      [explanationLocale]: e.target.value,
                    }))
                  }
                  className="w-full rounded-lg border border-border bg-background px-3 py-2 text-sm"
                  placeholder="Explanation text"
                />

                {currentExplanation?.assets && currentExplanation.assets.length > 0 ? (
                  <div className="mt-3 grid gap-2 md:grid-cols-2">
                    {currentExplanation.assets.map((asset) => (
                      <div key={asset.url} className="flex items-center justify-between rounded-lg border p-2">
                        <a href={asset.url} target="_blank" rel="noreferrer" className="truncate text-xs underline">
                          {asset.url}
                        </a>
                        <Button
                          variant="ghost"
                          size="icon"
                          onClick={async () => {
                            if (!currentExplanation) return;
                            await deleteExplanationAsset(currentExplanation.id, asset.url);
                            const refreshed = await fetchExplanationByQuestion(selectedQuestion.id);
                            setCurrentExplanation(refreshed);
                          }}
                        >
                          <Trash2 className="h-4 w-4 text-destructive" />
                        </Button>
                      </div>
                    ))}
                  </div>
                ) : null}

                <div className="mt-3 flex flex-wrap items-center gap-2">
                  <label className="inline-flex cursor-pointer items-center gap-2 rounded-md border px-3 py-2 text-sm">
                    <FileUp className="h-4 w-4" />
                    Add explanation assets
                    <input
                      hidden
                      multiple
                      type="file"
                      onChange={(e) => appendExplanationAssets(Array.from(e.target.files ?? []))}
                    />
                  </label>
                  <span className="text-xs text-muted-foreground">{explanationAssetDrafts.length} files queued</span>
                </div>

                {explanationAssetDrafts.length > 0 ? (
                  <div className="mt-3 space-y-2">
                    {explanationAssetDrafts.map((asset, index) => (
                      <div
                        key={`${asset.file.name}-${index}`}
                        draggable
                        onDragStart={() => setDraggingExplanationAssetIndex(index)}
                        onDragOver={(e) => e.preventDefault()}
                        onDrop={() => {
                          if (draggingExplanationAssetIndex === null) return;
                          setExplanationAssetDrafts((prev) => moveItem(prev, draggingExplanationAssetIndex, index));
                          setDraggingExplanationAssetIndex(null);
                        }}
                        className="grid grid-cols-1 gap-2 rounded-lg border p-2 md:grid-cols-[120px,1fr,auto] md:items-center"
                      >
                        <LocalAssetPreview file={asset.file} />
                        <div>
                          <p className="truncate text-sm font-medium">{asset.file.name}</p>
                          <p className="text-xs text-muted-foreground">{asset.type}</p>
                        </div>
                        <div className="flex items-center gap-1">
                          <Button
                            variant="ghost"
                            size="icon"
                            disabled={index === 0}
                            onClick={() => setExplanationAssetDrafts((prev) => moveItem(prev, index, index - 1))}
                          >
                            <ChevronUp className="h-4 w-4" />
                          </Button>
                          <Button
                            variant="ghost"
                            size="icon"
                            disabled={index === explanationAssetDrafts.length - 1}
                            onClick={() => setExplanationAssetDrafts((prev) => moveItem(prev, index, index + 1))}
                          >
                            <ChevronDown className="h-4 w-4" />
                          </Button>
                          <Button
                            variant="ghost"
                            size="icon"
                            onClick={() =>
                              setExplanationAssetDrafts((prev) => prev.filter((_, idx) => idx !== index))
                            }
                          >
                            <Trash2 className="h-4 w-4 text-destructive" />
                          </Button>
                        </div>
                      </div>
                    ))}
                  </div>
                ) : null}

                <div className="mt-3">
                  <Button onClick={() => void handleSaveExplanation()}>
                    {currentExplanation ? 'Update Explanation' : 'Create Explanation'}
                  </Button>
                  {currentExplanation ? (
                    <Button
                      variant="ghost"
                      className="ml-2 text-destructive"
                      onClick={async () => {
                        await deleteExplanation(currentExplanation.id);
                        setCurrentExplanation(null);
                        setExplanationDraft(emptyLocaleText());
                      }}
                    >
                      Delete Explanation
                    </Button>
                  ) : null}
                </div>
              </section>

              <section className="rounded-lg border p-4">
                <div className="mb-3 flex items-center justify-between">
                  <h4 className="text-sm font-semibold uppercase tracking-wide text-muted-foreground">Tips</h4>
                  <div className="inline-flex rounded-md border bg-background p-1">
                    {LANGUAGES.map((language) => (
                      <button
                        key={language.code}
                        onClick={() => setTipLocale(language.code)}
                        className={`rounded px-2 py-1 text-xs ${
                          tipLocale === language.code ? 'bg-primary text-primary-foreground' : 'text-muted-foreground'
                        }`}
                      >
                        {language.label}
                      </button>
                    ))}
                  </div>
                </div>

                <div className="space-y-2">
                  {(selectedQuestion.tips ?? []).map((tip) => (
                    <div key={tip.id} className="rounded-lg border bg-background/70 p-3">
                      <div className="flex items-start gap-2">
                        <textarea
                          rows={2}
                          defaultValue={tip.tip}
                          className="w-full rounded-lg border border-border bg-background px-3 py-2 text-sm"
                          onBlur={async (e) => {
                            const payload: UpdateTipRequest = {
                              tip: e.target.value,
                              translations: tip.translations,
                            };
                            await updateTip(tip.id, payload);
                            await refreshSelectedQuestion();
                          }}
                        />
                        <Button
                          variant="ghost"
                          size="icon"
                          onClick={async () => {
                            await deleteTip(tip.id);
                            await refreshSelectedQuestion();
                          }}
                        >
                          <Trash2 className="h-4 w-4 text-destructive" />
                        </Button>
                      </div>
                    </div>
                  ))}
                </div>

                <div className="mt-3 rounded-lg border border-dashed p-3">
                  <h5 className="mb-2 text-sm font-medium">Add Tip</h5>
                  <textarea
                    rows={2}
                    value={tipDraft[tipLocale]}
                    onChange={(e) =>
                      setTipDraft((prev) => ({
                        ...prev,
                        [tipLocale]: e.target.value,
                      }))
                    }
                    className="w-full rounded-lg border border-border bg-background px-3 py-2 text-sm"
                    placeholder={`Tip (${tipLocale.toUpperCase()})`}
                  />
                  <Button className="mt-2" onClick={() => void handleAddTip()}>
                    Add Tip
                  </Button>
                </div>
              </section>
            </div>
          )}

          <DialogFooter>
            <Button variant="outline" onClick={() => setDetailsOpen(false)}>
              Close
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      <Dialog open={deleteOpen} onOpenChange={setDeleteOpen}>
        <DialogContent className="max-w-md">
          <DialogHeader>
            <DialogTitle>Delete Question</DialogTitle>
          </DialogHeader>
          <p className="text-sm text-muted-foreground">
            This performs a soft delete and removes this question from active workflows.
          </p>
          <div className="rounded-lg border bg-muted/40 p-3 text-sm">{questionToDelete?.question}</div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setDeleteOpen(false)}>
              Cancel
            </Button>
            <Button ref={deleteButtonRef} variant="destructive" onClick={() => void handleDeleteQuestion()}>
              Delete
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}
